import{_ as e,o as t,c as i,S as r}from"./chunks/framework.DZlzLDBr.js";const h=JSON.parse('{"title":"Backups","description":"","frontmatter":{},"headers":[],"relativePath":"Backups.md","filePath":"Backups.md","lastUpdated":null}'),s={name:"Backups.md"};function l(o,a,n,c,u,p){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="backups" tabindex="-1">Backups <a class="header-anchor" href="#backups" aria-label="Permalink to &quot;Backups&quot;">​</a></h1><p>Last modified: 05/03/2026</p><h2 id="what-backups-are-for" tabindex="-1">What backups are for <a class="header-anchor" href="#what-backups-are-for" aria-label="Permalink to &quot;What backups are for&quot;">​</a></h2><p>Backups save your <strong>scheduling data</strong> so you can recover from mistakes or bad imports. They do not back up your note text.</p><h2 id="create-a-backup" tabindex="-1">Create a backup <a class="header-anchor" href="#create-a-backup" aria-label="Permalink to &quot;Create a backup&quot;">​</a></h2><ol><li>Open <strong>Settings → Reset</strong>.</li><li>Click <strong>Create backup now</strong>.</li></ol><p>The backup is saved immediately.</p><h2 id="automatic-backup-policy-anki-style-tiers" tabindex="-1">Automatic backup policy (Anki-style tiers) <a class="header-anchor" href="#automatic-backup-policy-anki-style-tiers" aria-label="Permalink to &quot;Automatic backup policy (Anki-style tiers)&quot;">​</a></h2><p>Sprout uses a hybrid retention policy with short-term and long-term snapshots. You can configure this in <strong>Settings → Data backup</strong>.</p><p>Default policy:</p><ul><li>8 recent backups (every 6 hours)</li><li>7 daily backups (every 1 day)</li><li>4 weekly backups (every 7 days)</li><li>1 monthly backup (every 30 days)</li><li>250 MB total backup size cap</li></ul><p>When total backup size exceeds the cap, Sprout prunes oldest tier entries first.</p><p>Routine backups use the <strong>Recent interval (hours)</strong> setting.</p><h2 id="restore-a-backup" tabindex="-1">Restore a backup <a class="header-anchor" href="#restore-a-backup" aria-label="Permalink to &quot;Restore a backup&quot;">​</a></h2><ol><li>In the backup table, find the backup you want.</li><li>Click <strong>Restore</strong>.</li><li>Confirm.</li></ol><p>Restoring replaces current scheduling data with older data.</p><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Restore overwrites your current scheduling state and review history. Reviews done after that backup was made are lost.</p></div><h2 id="delete-a-backup" tabindex="-1">Delete a backup <a class="header-anchor" href="#delete-a-backup" aria-label="Permalink to &quot;Delete a backup&quot;">​</a></h2><p>Click <strong>Delete</strong> next to a backup to remove it permanently. This action cannot be undone.</p><h2 id="what-is-included" tabindex="-1">What is included <a class="header-anchor" href="#what-is-included" aria-label="Permalink to &quot;What is included&quot;">​</a></h2><ul><li>card stages, intervals, stability, difficulty</li><li>review history</li><li>FSRS parameters</li><li>card-to-note mappings</li></ul><h2 id="what-is-not-included" tabindex="-1">What is not included <a class="header-anchor" href="#what-is-not-included" aria-label="Permalink to &quot;What is not included&quot;">​</a></h2><ul><li>Markdown note content</li><li>media files</li><li>plugin settings</li></ul><h2 id="when-to-create-backups" tabindex="-1">When to create backups <a class="header-anchor" href="#when-to-create-backups" aria-label="Permalink to &quot;When to create backups&quot;">​</a></h2><ul><li>before reset actions</li><li>before large imports (see <a href="./Anki-Export-&amp;-Import">Anki Export &amp; Import</a>)</li><li>regularly as a safety habit</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Backups are local-first and intended for recovery.</li><li>New backups include a sidecar integrity manifest (<code>.manifest.json</code>) with size + checksum.</li><li>Older backups without a manifest are still supported and can still be restored.</li><li>If backup files are missing or corrupted, use your most recent valid backup.</li></ul>',27)])])}const k=e(s,[["render",l]]);export{h as __pageData,k as default};
